def unify_mst_cost(n, m, edges):
    from heapq import heappop, heappush
    from collections import defaultdict

    def find(parent, i):
        if parent[i] == i:
            return i
        return find(parent, parent[i])

    def union(parent, rank, x, y):
        rootX = find(parent, x)
        rootY = find(parent, y)

        if rootX != rootY:
            if rank[rootX] > rank[rootY]:
                parent[rootY] = rootX
            elif rank[rootX] < rank[rootY]:
                parent[rootX] = rootY
            else:
                parent[rootY] = rootX
                rank[rootX] += 1

    def kruskal():
        mst_edges = []
        edges.sort(key=lambda x: x[2])
        parent = list(range(n))
        rank = [0] * n

        for u, v, w in edges:
            if find(parent, u) != find(parent, v):
                union(parent, rank, u, v)
                mst_edges.append((u, v, w))

        return mst_edges

    def count_operations(mst_edges):
        edge_count = defaultdict(int)
        for u, v, w in mst_edges:
            edge_count[(u, v)] += 1
            edge_count[(v, u)] += 1

        operations = 0
        for u, v, w in edges:
            if edge_count[(u, v)] > 1:
                operations += 1

        return operations

    mst_edges = kruskal()
    operations = count_operations(mst_edges)

    return operations

