def max_objects_packed(n, m, k, a):
    def can_pack(objects, boxes):
        for obj in objects:
            if not boxes:
                return False
            for i in range(len(boxes)):
                if boxes[i] >= obj:
                    boxes[i] -= obj
                    break
            else:
                return False
        return True

    left = 0
    right = n
    while left < right:
        mid = (left + right + 1) // 2
        if can_pack(a[:mid], [k] * m):
            left = mid
        else:
            right = mid - 1
    return left

