def min_chars_to_transmit(route):
    n = len(route)
    dp = [[float('inf')] * (n + 1) for _ in range(n + 1)]
    dp[0][0] = 0

    for i in range(1, n + 1):
        dp[i][0] = i
        dp[0][i] = i

    for i in range(1, n + 1):
        for j in range(1, n + 1):
            if route[i - 1] == route[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = min(dp[i - 1][j], dp[i][j - 1]) + 1

    return dp[n][n]

