def min_changes_to_ap(n, b):
    if n <= 2:
        return 0

    def is_ap(seq):
        diff = seq[1] - seq[0]
        for i in range(2, len(seq)):
            if seq[i] - seq[i-1] != diff:
                return False
        return True

    min_changes = float('inf')

    for i in range(n):
        for j in range(max(0, b[i]-1), min(b[i]+2, 10**9+1)):
            new_b = b[:]
            new_b[i] = j
            if is_ap(new_b):
                changes = sum(abs(x - y) for x, y in zip(b, new_b)) // 2
                min_changes = min(min_changes, changes)

    return min_changes if min_changes != float('inf') else -1

