def select_winner(n, outcomes):
    from collections import Counter
    counts = Counter(outcomes)
    unique_outcomes = [outcome for outcome, count in counts.items() if count == 1]
    if not unique_outcomes:
        return "none"
    max_unique = max(unique_outcomes)
    return str(outcomes.index(max_unique) + 1)

