def sort_matrix(n, m, matrix):
    row_inversions = [0] * n
    col_inversions = [0] * m

    for i in range(n):
        if sum(matrix[i]) % 2 != 0:
            for j in range(m):
                matrix[i][j] = 1 - matrix[i][j]
            row_inversions[i] = 1

    for j in range(m):
        col_sum = sum(matrix[i][j] for i in range(n))
        if col_sum % 2 != 0:
            for i in range(n):
                matrix[i][j] = 1 - matrix[i][j]
            col_inversions[j] = 1

    return row_inversions, col_inversions

