def count_good_observatories(N, M, H, roads):
    from collections import defaultdict

    graph = defaultdict(list)
    for A, B in roads:
        graph[A].append(B)
        graph[B].append(A)

    good_count = 0

    def dfs(node, parent):
        max_height = H[node - 1]
        for neighbor in graph[node]:
            if neighbor != parent:
                max_height = max(max_height, dfs(neighbor, node))
        if max_height < H[node - 1]:
            nonlocal good_count
            good_count += 1
        return max_height

    for i in range(1, N + 1):
        if not graph[i]:
            good_count += 1
        else:
            dfs(i, None)

    return good_count

