def max_segments(n, b, a, s):
    dp = [[0] * (b + 1) for _ in range(a + 1)]
    dp[0][0] = 1

    for i in range(1, n + 1):
        new_dp = [[0] * (b + 1) for _ in range(a + 1)]
        if s[i - 1] == 0:
            for j in range(b + 1):
                for k in range(a + 1):
                    if dp[j][k] > 0:
                        new_dp[j][k] += dp[j][k]
                        if j > 0:
                            new_dp[j - 1][k] += dp[j][k]
        else:
            for j in range(b + 1):
                for k in range(a + 1):
                    if dp[j][k] > 0:
                        new_dp[j][k] += dp[j][k]
                        if j > 0:
                            new_dp[j - 1][k] += dp[j][k]
                        if k > 0:
                            new_dp[j][k - 1] += dp[j][k]
        dp = new_dp

    return max(max(row) for row in dp)

